package main
import "fmt"

// The Interface (The Requirement)
type Speaker interface { Speak() string }

// Struct 1
type Dog struct{}
func (d Dog) Speak() string { return "Woof!" }

// Struct 2
type Cat struct{}
func (c Cat) Speak() string { return "Meow!" }

// This function accepts ANY type that fulfills 'Speaker'!
func MakeSound(s Speaker) {
    fmt.Println(s.Speak())
}

func main() {
    MakeSound(Dog{}) // Works!
    MakeSound(Cat{}) // Works!
}
